from dataclasses import dataclass
from enum import Enum

class GroundednessGate(Enum):
    PASS   = "pass"
    REVIEW = "review"
    BLOCK  = "block"

@dataclass
class GroundednessResult:
    score: float
    gate: GroundednessGate
    flagged_sentences: list[str]

def check_groundedness(
    answer: str,
    context: str,
    pass_threshold: float = 0.90,
    review_threshold: float = 0.70,
) -> GroundednessResult:
    result = nli_groundedness(answer, context)
    score = result["score"]
    flagged = [
        v["sentence"] for v in result["verdicts"] if not v["entailed"]
    ]
    if score >= pass_threshold:
        gate = GroundednessGate.PASS
    elif score >= review_threshold:
        gate = GroundednessGate.REVIEW
    else:
        gate = GroundednessGate.BLOCK
    return GroundednessResult(score=score, gate=gate, flagged_sentences=flagged)


# In a FastAPI endpoint:
def rag_respond(query: str, context: str, answer: str) -> dict:
    gr = check_groundedness(answer, context)
    if gr.gate == GroundednessGate.BLOCK:
        return {
            "answer": "I couldn't find a reliable answer in the provided documents.",
            "groundedness": gr.score,
            "flagged": gr.flagged_sentences,
        }
    if gr.gate == GroundednessGate.REVIEW:
        return {
            "answer": answer,
            "groundedness": gr.score,
            "warning": "Some claims may not be fully supported by the source documents.",
            "flagged": gr.flagged_sentences,
        }
    return {"answer": answer, "groundedness": gr.score}
